#define CudaCheck(code) { CudaCheckImpl((code), __FILE__, __LINE__); }

void CudaCheckImpl(cudaError_t cudaError, const char* file, int line) {
    if (cudaError != cudaSuccess) {
        throw std::runtime_error(
            std::string("Failure at ") + file + ":" + std::to_string(line) + " " +
            cudaGetErrorString(cudaError));
    }
}

std::vector<float> GenerateData(size_t nElems, size_t seed) {
    std::mt19937_64 gen{};
    gen.seed(seed);

    std::uniform_real_distribution<> dist(-1.0f, 1.0f);
    std::vector<float> res(nElems);
    for (auto& elem : res) {
        elem = dist(gen);
    }

    return res;
}

float* GenerateDevicePtr(const std::vector<float>& hostData) {
    float* devicePtr = nullptr;
    CudaCheck(cudaMalloc(&devicePtr, hostData.size() * sizeof(float)));
    CudaCheck(cudaMemcpy(devicePtr, hostData.data(), hostData.size() * sizeof(float), cudaMemcpyHostToDevice));
    return devicePtr;
}

